const NAV_ICONS: Record<string, SvgIconComponent> = {
  home: HomeNavIcon as SvgIconComponent,
  calendar_month: CalendarNavIcon as SvgIconComponent,
  chat: ConversationNavIcon as SvgIconComponent,
  person: GroupNavIcon as SvgIconComponent,
  featured_play_list: DocumentNavIcon as SvgIconComponent,
  medication: LargeMedicalBuildingNavIcon as SvgIconComponent,
  bar_chart: ChartBoxNavIcon as SvgIconComponent,
  flag: FlagNavIcon as SvgIconComponent,
  how_to_reg: PersonCheckNavIcon as SvgIconComponent,
  show_chart: BarChartNavIcon as SvgIconComponent,
  inbox: InboxRevenueNavIcon as SvgIconComponent,
  assignment: ReceiptPurchaseRecordNavIcon as SvgIconComponent,
  receipt_long: ReceiptNavIcon as SvgIconComponent,
  description: DocumentNavIcon as SvgIconComponent,
  credit_card: WalletAltNavIcon as SvgIconComponent,
  request_quote: StatementsNavIcon as SvgIconComponent,
  settings: SettingsFooterNavIcon as SvgIconComponent,
  logout: LogoutFooterNavIcon as SvgIconComponent,
  keyboard_arrow_down: KeyboardArrowDownOutlined,
  chevron_right: ChevronRightOutlined,
  chevron_left: ChevronLeftOutlined,
};

const SIDEBAR_WIDTH = 180;
const SIDEBAR_COLLAPSED = 44;
const ITEM_HEIGHT = 28;
const NAV_ITEM_FONT_SIZE = 14;
const SECTION_HEADER_FONT_SIZE = 11;

type NavItemConfig = {
  id: string;
  label: string;
  icon: string;
  path?: string;
  fill?: boolean;
};

const topNavItems: NavItemConfig[] = [
  { id: 'home', label: 'Home', icon: 'home', path: '/' },
  { id: 'visits', label: 'Visits', icon: 'calendar_month' },
  { id: 'messages', label: 'Message & Tasks', icon: 'chat' },
];

const medicalRecordsItems: NavItemConfig[] = [
  { id: 'patients', label: 'Patients', icon: 'person', fill: true, path: '/patients' },
  { id: 'orders', label: 'Orders', icon: 'featured_play_list' },
  { id: 'pharmacies', label: 'Pharmacies', icon: 'medication' },
];

const businessItems: NavItemConfig[] = [
  { id: 'overview', label: 'Overview', icon: 'bar_chart' },
  { id: 'lead-management', label: 'Lead Management', icon: 'flag' },
  { id: 'outreach', label: 'Outreach', icon: 'how_to_reg' },
  { id: 'reports', label: 'Reports', icon: 'show_chart' },
];

const revenueCycleItems: NavItemConfig[] = [
  { id: 'encounters', label: 'Encounters', icon: 'inbox' },
  { id: 'claims', label: 'Claims', icon: 'assignment' },
  { id: 'remittances', label: 'Remittances', icon: 'receipt_long' },
  { id: 'eobs', label: 'EoBs', icon: 'description' },
  { id: 'payments', label: 'Payments', icon: 'credit_card' },
  { id: 'statements', label: 'Statements', icon: 'request_quote' },
];

const bottomNavItems: NavItemConfig[] = [
  { id: 'preferences', label: 'Preferences', icon: 'settings' },
  { id: 'logout', label: 'Log Out', icon: 'logout' },
];

function NavItem({
  label,
  icon,
  path,
  active,
  collapsed,
}: {
  label: string;
  icon: string;
  path?: string;
  active?: boolean;
  collapsed: boolean;
}) {
  const content = (
    <>
      <ListItemIcon
        sx={{
          minWidth: collapsed ? 'auto' : 18,
          justifyContent: 'center',
          color: active ? 'primary.dark' : 'text.secondary',
        }}
      >
        {(() => {
          const IconComponent = NAV_ICONS[icon];
          return IconComponent ? <IconComponent sx={{ fontSize: 18 }} /> : null;
        })()}
      </ListItemIcon>
      {!collapsed && (
        <ListItemText
          primary={label}
          primaryTypographyProps={{
            fontSize: NAV_ITEM_FONT_SIZE,
            lineHeight: '22px',
            fontWeight: active ? 500 : 400,
            color: active ? 'primary.dark' : 'text.secondary',
          }}
        />
      )}
    </>
  );

  const sx = {
    height: ITEM_HEIGHT,
    minHeight: ITEM_HEIGHT,
    maxHeight: ITEM_HEIGHT,
    ...(collapsed && {
      width: ITEM_HEIGHT,
      minWidth: ITEM_HEIGHT,
      maxWidth: ITEM_HEIGHT,
    }),
    py: 0,
    px: collapsed ? 0 : 1,
    gap: 0.75,
    borderRadius: 1,
    justifyContent: collapsed ? 'center' : 'flex-start',
    bgcolor: active ? 'rgba(0, 102, 70, 0.2)' : 'transparent',
    '&:hover': {
      bgcolor: active ? 'rgba(0, 102, 70, 0.25)' : 'action.hover',
    },
  };

  const button = path ? (
    <ListItemButton component={Link} to={path} sx={sx}>
      {content}
    </ListItemButton>
  ) : (
    <ListItemButton sx={sx}>{content}</ListItemButton>
  );

  if (collapsed) {
    return (
      <Tooltip
        title={label}
        placement="right"
        enterDelay={200}
        leaveDelay={0}
        arrow
        slotProps={{
          tooltip: {
            sx: {
              bgcolor: '#fff',
              color: 'text.primary',
              border: '1px solid rgba(0, 0, 0, 0.1)',
              boxShadow: '0 2px 8px rgba(0, 0, 0, 0.08)',
              fontSize: 12,
              fontWeight: 500,
            },
          },
          arrow: {
            sx: {
              color: '#fff',
              '&::before': {
                border: '1px solid rgba(0, 0, 0, 0.1)',
                backgroundColor: '#fff',
                boxSizing: 'border-box',
              },
            },
          },
        }}
      >
        {button}
      </Tooltip>
    );
  }

  return button;
}

function SectionHeaderButton({
  label,
  expanded,
  onClick,
  collapsed,
}: {
  label: string;
  expanded: boolean;
  onClick: () => void;
  collapsed: boolean;
}) {
  if (collapsed) return null;
  return (
    <ListItemButton
      onClick={onClick}
      sx={{
        height: ITEM_HEIGHT,
        minHeight: ITEM_HEIGHT,
        maxHeight: ITEM_HEIGHT,
        py: 0,
        px: 1,
        gap: '2px',
        borderRadius: 1,
        justifyContent: 'flex-start',
        '&:hover': {
          bgcolor: 'action.hover',
        },
      }}
    >
      <Box
        component="span"
        sx={{
          flex: '0 0 auto',
          fontSize: SECTION_HEADER_FONT_SIZE,
          fontWeight: 700,
          lineHeight: '18px',
          color: 'text.secondary',
        }}
      >
        {label}
      </Box>
      <KeyboardArrowDownOutlined
        sx={{
          fontSize: 14,
          transform: expanded ? 'rotate(0deg)' : 'rotate(-90deg)',
          transition: 'transform 0.2s',
        }}
      />
    </ListItemButton>
  );
}

export interface SideNavProps {
  collapsed: boolean;
  onToggle: () => void;
}

export function SideNav({ collapsed, onToggle }: SideNavProps) {
  const location = useLocation();
  const width = collapsed ? SIDEBAR_COLLAPSED : SIDEBAR_WIDTH;

  const [medicalRecordsOpen, setMedicalRecordsOpen] = useState(true);
  const [businessOpen, setBusinessOpen] = useState(true);
  const [revenueCycleOpen, setRevenueCycleOpen] = useState(true);

  return (
    <Box
      sx={{
        width,
        flexShrink: 0,
        display: 'flex',
        flexDirection: 'column',
        transition: (theme) =>
          theme.transitions.create('width', {
            easing: theme.transitions.easing.sharp,
            duration: theme.transitions.duration.enteringScreen,
          }),
      }}
    >
      {/* Logo + collapse */}
      <Box
        sx={{
          py: 0.25,
          px: 1,
          display: 'flex',
          alignItems: 'center',
          gap: 1.5,
          minHeight: 40,
          justifyContent: collapsed ? 'center' : 'flex-start',
        }}
      >
        {!collapsed && (
          <Box
            sx={{
              width: 32,
              height: 32,
              flexShrink: 0,
              borderRadius: 1,
              bgcolor: 'primary.main',
            }}
          />
        )}
      </Box>

      {/* Menu groups: 12px between groups; 24px bottom padding inside each list (only visible when expanded) */}
      <Box
        sx={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          minHeight: 0,
          px: 1,
          py: 3,
        }}
      >
        <Box
          sx={{
            flex: 1,
            display: 'flex',
            flexDirection: 'column',
            gap: 0.5,
            minHeight: 0,
            overflow: 'hidden',
            overflowY: 'auto',
          }}
        >
          {/* Universal (no heading) */}
          <Box component="nav" aria-label="Main">
            <List disablePadding sx={{ display: 'flex', flexDirection: 'column', gap: 0.25, pb: collapsed ? 0.5 : 3 }}>
              {topNavItems.map((item) => (
                <NavItem
                  key={item.id}
                  label={item.label}
                  icon={item.icon}
                  path={item.path}
                  active={item.path === location.pathname}
                  collapsed={collapsed}
                />
              ))}
            </List>
          </Box>
          {collapsed && (
            <Box sx={{ display: 'flex', justifyContent: 'center', py: 0.5 }}>
              <Box sx={{ width: 20, height: 2, bgcolor: 'grey.400', borderRadius: 1 }} />
            </Box>
          )}

          {/* Medical Records */}
          <Box component="nav" aria-label="Medical Records">
            <List disablePadding>
              <SectionHeaderButton
                label="Medical Records"
                expanded={medicalRecordsOpen}
                onClick={() => setMedicalRecordsOpen((o) => !o)}
                collapsed={collapsed}
              />
            </List>
            <Collapse in={medicalRecordsOpen}>
              <List disablePadding sx={{ display: 'flex', flexDirection: 'column', gap: 0.25, pb: collapsed ? 0.5 : 3 }}>
                {medicalRecordsItems.map((item) => (
                  <NavItem
                    key={item.id}
                    label={item.label}
                    icon={item.icon}
                    path={item.path}
                    active={item.path === location.pathname}
                    collapsed={collapsed}
                  />
                ))}
              </List>
            </Collapse>
          </Box>
          {collapsed && (
            <Box sx={{ display: 'flex', justifyContent: 'center', py: 0.5 }}>
              <Box sx={{ width: 20, height: 2, bgcolor: 'grey.400', borderRadius: 1 }} />
            </Box>
          )}

          {/* Business */}
          <Box component="nav" aria-label="Business">
            <List disablePadding>
              <SectionHeaderButton
                label="Business"
                expanded={businessOpen}
                onClick={() => setBusinessOpen((o) => !o)}
                collapsed={collapsed}
              />
            </List>
            <Collapse in={businessOpen}>
              <List disablePadding sx={{ display: 'flex', flexDirection: 'column', gap: 0.25, pb: collapsed ? 0.5 : 3 }}>
                {businessItems.map((item) => (
                  <NavItem
                    key={item.id}
                    label={item.label}
                    icon={item.icon}
                    path={item.path}
                    active={item.path === location.pathname}
                    collapsed={collapsed}
                  />
                ))}
              </List>
            </Collapse>
          </Box>
          {collapsed && (
            <Box sx={{ display: 'flex', justifyContent: 'center', py: 0.5 }}>
              <Box sx={{ width: 20, height: 2, bgcolor: 'grey.400', borderRadius: 1 }} />
            </Box>
          )}

          {/* Revenue Cycle */}
          <Box component="nav" aria-label="Revenue Cycle">
            <List disablePadding>
              <SectionHeaderButton
                label="Revenue Cycle"
                expanded={revenueCycleOpen}
                onClick={() => setRevenueCycleOpen((o) => !o)}
                collapsed={collapsed}
              />
            </List>
            <Collapse in={revenueCycleOpen}>
              <List disablePadding sx={{ display: 'flex', flexDirection: 'column', gap: 0.25, pb: collapsed ? 0.5 : 3 }}>
                {revenueCycleItems.map((item) => (
                  <NavItem
                    key={item.id}
                    label={item.label}
                    icon={item.icon}
                    path={item.path}
                    active={item.path === location.pathname}
                    collapsed={collapsed}
                  />
                ))}
              </List>
            </Collapse>
          </Box>
          {collapsed && (
            <Box sx={{ display: 'flex', justifyContent: 'center', py: 0.5 }}>
              <Box sx={{ width: 20, height: 2, bgcolor: 'grey.400', borderRadius: 1 }} />
            </Box>
          )}
        </Box>

        <List disablePadding sx={{ display: 'flex', flexDirection: 'column', gap: 0.25, flexShrink: 0 }}>
          {bottomNavItems.map((item) => (
            <NavItem
              key={item.id}
              label={item.label}
              icon={item.icon}
              path={item.path}
              active={item.path === location.pathname}
              collapsed={collapsed}
            />
          ))}
        </List>
      </Box>
    </Box>
  );
}
